-- Table: activity_log
CREATE TABLE `activity_log` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `log_name` VARCHAR(255), `description` text not null, `subject_type` VARCHAR(255), `subject_id` INT, `event` VARCHAR(255), `causer_type` VARCHAR(255), `causer_id` INT, `properties` text, `batch_uuid` VARCHAR(255), `created_at` DATETIME, `updated_at` DATETIME);


-- Table: cache
