CREATE TABLE `lunar_tax_rate_amounts` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_class_id` INT, `tax_rate_id` INT, `percentage` numeric not null, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_class_id`) references `lunar_tax_classes`(`id`), foreign key(`tax_rate_id`) references `lunar_tax_rates`(`id`));


-- Table: lunar_tax_rates
CREATE TABLE `lunar_tax_rates` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_zone_id` INT, `priority` INT not null default '1', `name` VARCHAR(255) not null, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_zone_id`) references `lunar_tax_zones`(`id`));


-- Table: lunar_tax_zone_countries
CREATE TABLE `lunar_tax_zone_countries` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_zone_id` INT, `country_id` INT, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_zone_id`) references `lunar_tax_zones`(`id`), foreign key(`country_id`) references `lunar_countries`(`id`));

-- Table: lunar_tax_zone_customer_groups
CREATE TABLE `lunar_tax_zone_customer_groups` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_zone_id` INT, `customer_group_id` INT, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_zone_id`) references `lunar_tax_zones`(`id`), foreign key(`customer_group_id`) references `lunar_customer_groups`(`id`));

-- Table: lunar_tax_zone_postcodes
CREATE TABLE `lunar_tax_zone_postcodes` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_zone_id` INT, `country_id` INT, `postcode` VARCHAR(255) not null, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_zone_id`) references `lunar_tax_zones`(`id`), foreign key(`country_id`) references `lunar_countries`(`id`));

-- Table: lunar_tax_zone_states
CREATE TABLE `lunar_tax_zone_states` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tax_zone_id` INT, `state_id` INT, `created_at` DATETIME, `updated_at` DATETIME, foreign key(`tax_zone_id`) references `lunar_tax_zones`(`id`), foreign key(`state_id`) references `lunar_states`(`id`));

-- Table: lunar_tax_zones
CREATE TABLE `lunar_tax_zones` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `name` VARCHAR(255) not null, `zone_type` VARCHAR(255) not null, `price_display` VARCHAR(255) not null, `active` tinyint(1) not null, `default` tinyint(1) not null, `created_at` DATETIME, `updated_at` DATETIME);


-- Table: lunar_transactions
CREATE TABLE `lunar_transactions` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `order_id` INT not null, `success` tinyint(1) not null, `driver` VARCHAR(255) not null, `amount` INT not null, `reference` VARCHAR(255) not null, `status` VARCHAR(255) not null, `notes` VARCHAR(255), `card_type` VARCHAR(255) not null, `last_four` VARCHAR(255), `meta` text, `created_at` DATETIME, `updated_at` DATETIME, `parent_transaction_id` INT, `captured_at` DATETIME, `type` VARCHAR(255) not null default ('capture'), foreign key(`order_id`) references lunar_orders(`id`) on delete no action on update no action, foreign key(`parent_transaction_id`) references lunar_transactions(`id`) on delete no action on update no action);

-- Table: lunar_urls
CREATE TABLE `lunar_urls` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `language_id` INT not null, `element_type` VARCHAR(255) not null, `element_id` INT not null, `slug` VARCHAR(255) not null, `default` tinyint(1) not null default '0', `created_at` DATETIME, `updated_at` DATETIME, foreign key(`language_id`) references `lunar_languages`(`id`));


-- Table: media
CREATE TABLE `media` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `model_type` VARCHAR(255) not null, `model_id` INT not null, `uuid` VARCHAR(255), `collection_name` VARCHAR(255) not null, `name` VARCHAR(255) not null, `file_name` VARCHAR(255) not null, `mime_type` VARCHAR(255), `disk` VARCHAR(255) not null, `conversions_disk` VARCHAR(255), `size` INT not null, `manipulations` text not null, `custom_properties` text not null, `generated_conversions` text not null, `responsive_images` text not null, `order_column` INT, `created_at` DATETIME, `updated_at` DATETIME);


-- Table: migrations
CREATE TABLE `migrations` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `migration` VARCHAR(255) not null, `batch` INT not null);


-- Table: model_has_permissions
CREATE TABLE `model_has_permissions` (`permission_id` INT not null, `model_type` VARCHAR(255) not null, `model_id` INT not null, foreign key(`permission_id`) references `permissions`(`id`) on delete cascade, primary key (`permission_id`, `model_id`, `model_type`));

-- Table: model_has_roles
CREATE TABLE `model_has_roles` (`role_id` INT not null, `model_type` VARCHAR(255) not null, `model_id` INT not null, foreign key(`role_id`) references `roles`(`id`) on delete cascade, primary key (`role_id`, `model_id`, `model_type`));

-- Table: password_reset_tokens
CREATE TABLE `password_reset_tokens` (`email` VARCHAR(255) not null, `token` VARCHAR(255) not null, `created_at` DATETIME, primary key (`email`));

-- Table: permissions
CREATE TABLE `permissions` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `name` VARCHAR(255) not null, `guard_name` VARCHAR(255) not null, `created_at` DATETIME, `updated_at` DATETIME);


-- Table: personal_access_tokens
CREATE TABLE `personal_access_tokens` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `tokenable_type` VARCHAR(255) not null, `tokenable_id` INT not null, `name` text not null, `token` VARCHAR(255) not null, `abilities` text, `last_used_at` DATETIME, `expires_at` DATETIME, `created_at` DATETIME, `updated_at` DATETIME);

-- Table: role_has_permissions
CREATE TABLE `role_has_permissions` (`permission_id` INT not null, `role_id` INT not null, foreign key(`permission_id`) references `permissions`(`id`) on delete cascade, foreign key(`role_id`) references `roles`(`id`) on delete cascade, primary key (`permission_id`, `role_id`));

-- Table: roles
CREATE TABLE `roles` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `name` VARCHAR(255) not null, `guard_name` VARCHAR(255) not null, `created_at` DATETIME, `updated_at` DATETIME);


-- Table: sessions
CREATE TABLE `sessions` (`id` VARCHAR(255) not null, `user_id` INT, `ip_address` VARCHAR(255), `user_agent` text, `payload` text not null, `last_activity` INT not null, primary key (`id`));


-- Table: users
CREATE TABLE `users` (`id` INT AUTO_INCREMENT PRIMARY KEY not null, `name` VARCHAR(255) not null, `email` VARCHAR(255) not null, `email_verified_at` DATETIME, `password` VARCHAR(255) not null, `remember_token` VARCHAR(255), `created_at` DATETIME, `updated_at` DATETIME);




